module alu #(
    parameter ADD = 6'b100000,
    parameter ADDU = 6'b100001,
    parameter SUB = 6'b100010,
    parameter SUBU = 6'b100011,
    parameter AND = 6'b100100,
    parameter OR = 6'b100101,
    parameter XOR = 6'b100110,
    parameter NOR = 6'b100111,
    parameter SLT = 6'b101010,
    parameter SLTU = 6'b101011,
    parameter SLL = 6'b000000,
    parameter SRL = 6'b000010,
    parameter SRA = 6'b000011,
    parameter SLLV = 6'b000100,
    parameter SRLV = 6'b000110,
    parameter SRAV = 6'b000111,
    parameter LUI = 6'b001111
) (
    input [31:0] a,
    input [31:0] b,
    input [5:0] aluc,
    output [31:0] r,
    output zero,
    output reg carry,
    output negative,
    output reg overflow,
    output flag
);
    reg [31:0] res;
    assign r = res;
    assign zero = &res;
    assign negative = res[31];
    assign flag = (aluc == SLT || aluc == SLTU) ? res[0] : 1'bz;
    always @(*) begin
        case (aluc)
            ADD: {carry, res} = {a[31], a} + {b[31], b};
            ADDU: {overflow, res} = a + b;
            SUB: {carry, res} = {a[31], a} - {b[31], b};
            SUBU: {overflow, res} = a - b;
            AND: res = a & b;
            OR: res = a | b;
            XOR: res = a ^ b;
            NOR: res = ~(a | b);
            SLT: res = $signed(a) < $signed(b) ? 32'd1 : 32'd0;
            SLTU: res = a < b ? 32'd1 : 32'd0;
            SLL: res = b << a[4:0];
            SRL: res = b >> a[4:0];
            SRA: res = $signed(b) >>> a[4:0];
            SLLV: res = b << a[4:0];
            SRLV: res = b >> a[4:0];
            SRAV: res = $signed(b) >>> a[4:0];
            LUI: res = {b[15:0], 16'd0};
            default: res = 32'bx;
        endcase
    end
endmodule
